import{c as o,Q as e,j as a,m as r}from"./chunks/framework.hhGiamYR.js";const c=JSON.parse('{"title":"不要责怪民众——马基雅维利关于领导责任最刺耳的话","description":"","frontmatter":{"date":"2026-06-14T00:00:00.000Z","title":"不要责怪民众——马基雅维利关于领导责任最刺耳的话"},"headers":[],"relativePath":"research/dont-blame-the-people/index.md","filePath":"research/dont-blame-the-people/index.md"}'),p={name:"research/dont-blame-the-people/index.md"};function u(n,t,l,q,i,s){return e(),a("div",null,[...t[0]||(t[0]=[r('<p>在文艺复兴时期的意大利，当一个城邦被外国军队洗劫、当一支军队在战场上一触即溃、当一个共和国陷入内乱，最常见的声音是什么？&quot;士兵不行。&quot;&quot;人民懦弱。&quot;&quot;运气不好。&quot;马基雅维利用他全部的政治著作，对所有这些声音给出了同一个回答：<strong>住口。不是民众的错。是你的错。</strong></p><p>这不是一种道德姿态。这是马基雅维利从十四年外交与行政生涯中提炼出来的、关于领导责任的实效法则。他把它写进了《兵法》卷七最有力量的一段话里，也把它铺展在《君主论》第十四章、第二十四章中。这段话构成了他的第十三条信条——&quot;责在君主，不在民众&quot;——同时也可能是他最让所有统治者不舒服的一句话。</p><h2 id="那块剖料拙劣的大理石" tabindex="-1">那块剖料拙劣的大理石 <a class="header-anchor" href="#那块剖料拙劣的大理石" aria-label="Permalink to &quot;那块剖料拙劣的大理石&quot;">​</a></h2><p>《兵法》卷七中有一段被严重低估的论述。法布里齐奥·科洛纳——马基雅维利借他之口说话——已经花了六卷书的篇幅详细说明了如何选拔士兵、如何排兵布阵、如何训练、如何扎营、如何在战场上调动。到了卷七，他说：讲了这么多，有什么用呢？意大利的问题根本不在于士兵，而在于用士兵的人。</p><blockquote><p>📖 <strong>原文</strong>：《兵法》卷七，第229-231句</p><p>&quot;不过，还是让我们回来谈意大利人吧。由于缺乏明智的君主，他们一直没有得到任何好的安排；而且，由于缺乏西班牙人有的那种必需，他们一直没有靠自己造就任何好的安排，结果他们依旧是全世界的笑柄。就此，不要责怪民众，但确实要责怪他们的君主。他们业已为此受到惩罚，因为自己的愚昧无知而受到了公正的惩罚，那就是可耻地亡国，全无美德的范例。&quot;</p><p>— 法布里齐奥·科洛纳，《用兵之道》卷七</p><p>📖 <a href="https://niflhum.top/machiavelli-library/library/machiavelli/art-of-war/book07.md" target="_blank" rel="noreferrer">阅读全文</a></p></blockquote><p>这之后紧接着是一个雕塑师的比喻，它是马基雅维利所有著作中最凝练的领导力隐喻：&quot;任何一位高明的雕塑师都不会相信他能从一块剖料拙劣的大理石中制作出一座漂亮的雕像；然而，从一块未加工过的大理石中，他可大有理由作此设想。&quot;（第235句）一块未经加工的石头，里面可能藏着一尊杰作——只是需要一个懂得下刀的人。而一块被拙劣切割过的石头，无论谁来接手，都已经废了。</p><p>马基雅维利的意思是：意大利的民众就像那块被拙劣切割的大理石。不是石头的材质不好——是前面的雕塑师把它毁了。瑞士人有&quot;天然习俗&quot;、西班牙人有&quot;必需使然&quot;，意大利人有什么？有君主。但&quot;由于缺乏明智的君主&quot;，他们没有得到任何好的安排。</p><p>这个论证的激进之处在于：它完全颠倒了常见的推责逻辑。不是&quot;我们之所以失败，是因为意大利人天生不适合当兵&quot;；而是&quot;意大利人之所以不适合当兵，是因为从来没有人认真地训练过他们&quot;。责任的箭头从下往上指。当整个系统崩溃时，该看的是系统的设计者，而不是被塞进系统里的人。</p><h2 id="那些在自己的书斋里写漂亮信的君主" tabindex="-1">那些在自己的书斋里写漂亮信的君主 <a class="header-anchor" href="#那些在自己的书斋里写漂亮信的君主" aria-label="Permalink to &quot;那些在自己的书斋里写漂亮信的君主&quot;">​</a></h2><p>紧接着，法布里齐奥对意大利君主的生活方式发动了一场毫不留情的讽刺。这段话长达数行，一气呵成，每一个分句都是一把匕首：</p><blockquote><p>📖 <strong>原文</strong>：《兵法》卷七，第236-237句</p><p>&quot;在尝到阿尔卑斯山外人战争的打击之前，我们的意大利君主们惯常以为对一位君主来说懂得下面的事就足够了：如何在自己的书斋里构思一份措辞犀利的答复，如何撰写一封辞藻优美的书信，如何在自己的言行中显示机智敏捷，如何编造一场骗局，如何饰以宝石黄金，如何寝眠饮食堂皇过人，如何身边保有众多淫色，如何贪婪自大地统治臣民，如何百无聊赖腐败堕落，如何依凭宠幸提升军职，如何鄙视可能向其展示任何可赞之道的人士，如何欲使自己的演说成为神谕应答。这些可怜虫全不料想自己正在准备让自己成为无论什么袭击者的砧上肉。&quot;</p><p>— 法布里齐奥·科洛纳，《用兵之道》卷七</p><p>📖 <a href="https://niflhum.top/machiavelli-library/library/machiavelli/art-of-war/book07.md" target="_blank" rel="noreferrer">阅读全文</a></p></blockquote><p>这段话的杀伤力在于它的具体性。它没有泛泛地说&quot;统治者们不务正业&quot;，而是一条一条地列出了他们实际在做的事：写漂亮的信、穿珠宝黄金的衣服、把宠幸的人塞进军职、把自己的话当作神谕、在床上和食物上挥霍。注意这个清单包含了什么——也注意它<strong>没有</strong>包含什么。没有一条关于如何选拔士兵。没有一条关于如何训练军队。没有一条关于如何在战场上指挥。</p><p>然后，马基雅维利用一个短句把整个清单钉死：&quot;由此导致了1494年的巨大恐怖、突然逃亡和非凡损失；由此，意大利三个非常强大的邦国惨遭洗劫和毁坏。&quot;1494年——法国国王查理八世率军穿过意大利，如入无人之境。那不勒斯、米兰、佛罗伦萨——这些曾经强大的邦国，在真正的军队面前原形毕露。那不是命运的偶然一击，那是&quot;那些可怜虫&quot;自食其果。</p><h2 id="君主忽略了唯一该做的事" tabindex="-1">君主忽略了唯一该做的事 <a class="header-anchor" href="#君主忽略了唯一该做的事" aria-label="Permalink to &quot;君主忽略了唯一该做的事&quot;">​</a></h2><p>在《君主论》第十四章中，马基雅维利给君主下达了一个近乎绝对的命令——它简短到只有一句话，却几乎定义了整本书的核心：</p><blockquote><p>📖 <strong>原文</strong>：《君主论》第14章</p><p>&quot;一位君主除了战争及其规章制度和训练之外，不应该有其他的目标、其他任何的思想，也不应该把其他任何事情作为他的技艺，因为这是发号施令者应当关注的唯一技艺。它的效力不仅能够使那些凭出身成为君主的人维持地位，而且多次使那些平民运道的人跃居君主之位；反之，我们则看到，君主一旦考虑安逸享乐甚于整军经武，就会失去他们的国家。导致你失去国家的头一个原因就是忽略了这种技艺，而使你获取国家的原因就是你精通这种技艺。&quot;</p><p>— 尼科洛·马基雅维利，《君主论》第14章</p><p>📖 <a href="https://niflhum.top/machiavelli-library/library/machiavelli/prince/prince-cn-full.md" target="_blank" rel="noreferrer">阅读全文</a></p></blockquote><p>这不是一个建议。这是一个因果律。精通这种技艺 → 获取国家。忽略这种技艺 → 失去国家。马基雅维利举的例子是弗朗切斯科·斯福尔扎——他靠武装自己从一个平民变成了米兰公爵。他的儿子们呢？他们&quot;躲避军事的艰苦，结果由公爵降为平民。&quot;不是命运把他们拉下来的——是他们自己松了手。</p><p>第十四章真正令人不安的地方是它把&quot;忽略首要技艺&quot;定义为了一种<strong>道德失败</strong>，而不仅仅是战略失误。马基雅维利说君主在和平时期&quot;绝不应该让自己的思想离开军事训练问题&quot;——不是&quot;可以关注&quot;，是&quot;绝不&quot;。这意味着那些在书斋里写漂亮信的君主，不是不懂，而是懈怠。他们不是在面对一个复杂的难题——他们是在逃避一个简单的义务。</p><h2 id="不应该责难机运-而应该责难自己的惰怠无能" tabindex="-1">&quot;不应该责难机运，而应该责难自己的惰怠无能&quot; <a class="header-anchor" href="#不应该责难机运-而应该责难自己的惰怠无能" aria-label="Permalink to &quot;&quot;不应该责难机运，而应该责难自己的惰怠无能&quot;&quot;">​</a></h2><p>这个论证在《君主论》第二十四章达到了最直白的表述。在逐一分析了那些失去国家的意大利君主——那不勒斯国王、米兰公爵等等——之后，马基雅维利拒绝给他们任何台阶：</p><blockquote><p>📖 <strong>原文</strong>：《君主论》第24章</p><p>&quot;因此，我们的这些君主们，曾经享有其君主国许多年而后来失去了它们，他们不应该责难机运而应该责难自己的惰怠无能。在天气好的时候从不考虑可能出现的变化（在风和日丽的时候想不到暴风雨，这是人类共同的缺陷），一旦恶劣的天气来临，他们就只想到逃跑而不是保护自己。……只有那些依靠你自己和你的德能的防卫之道，才是有效的、可靠的、持久的。&quot;</p><p>— 尼科洛·马基雅维利，《君主论》第24章</p><p>📖 <a href="https://niflhum.top/machiavelli-library/library/machiavelli/prince/prince-cn-full.md" target="_blank" rel="noreferrer">阅读全文</a></p></blockquote><p>&quot;不应该责难机运而应该责难自己的惰怠无能&quot;——<em>non si debbino accusare la fortuna, ma la ignavia loro</em>。在意大利原文中，<em>ignavia</em> 这个词比中文&quot;惰怠无能&quot;更尖锐——它包含了懒惰、怯懦和无能三重意思。马基雅维利把整章关于机运（fortuna）的理论——他在第25章才正式展开它——压在这一句话下面：就算命运掌控一半，剩下的那一半你没有做到，怨谁？</p><p>注意他紧接着的诊断：&quot;在风和日丽的时候想不到暴风雨，这是人类共同的缺陷。&quot;他用了&quot;人类共同的&quot;（<em>commune difetto</em>）——不是意大利人特有的，不是某个阶层特有的，而是<strong>每个人</strong>都容易犯的错误。这句话的潜台词是：正因为这是人类共同的缺陷，领导者才更应该克服它。普通人在晴天忘记带伞可以被原谅；掌握一国命运的人不可以。</p><h2 id="自下而上的责任箭头" tabindex="-1">自下而上的责任箭头 <a class="header-anchor" href="#自下而上的责任箭头" aria-label="Permalink to &quot;自下而上的责任箭头&quot;">​</a></h2><p>把《兵法》卷七、《君主论》第十四章和《君主论》第二十四章放在一起看，马基雅维利关于领导责任的论述呈现出一种罕见的自洽。</p><p>首先，君主有<strong>唯一的义务</strong>——战争和它的组织与训练。这不是因为马基雅维利好战，而是因为如果这项义务没有被履行，其他一切——法律、文化、贸易、自由——都将化为泡影。法国人1494年的行军证明了这一点。</p><p>其次，这个义务的失败<strong>不能转嫁给任何人</strong>。你可以怪瑞士人天然素质好，怪西班牙人走投无路所以拼命——但最终，&quot;他们是全世界的笑柄&quot;的原因，不是他们的士兵不如瑞士人，而是他们的君主从来没有像瑞士人那样系统地训练过士兵，也从来没有给意大利人创造过西班牙人那种&quot;不打就死&quot;的必需。</p><p>第三，失败了之后，<strong>最不该怪的恰恰是机运</strong>。马基雅维利同意机运占据一半——他在第25章把这一点讲得很清楚——但他坚决反对把失败归因于机运，因为在风和日丽的那些年里，那些君主原本可以做的事情一件都没有做。把失败归咎于机运，是对&quot;那一半由你支配&quot;的否定。</p><p>最后，这个论证有一个未经言明但贯穿始终的前提：<strong>没有人天生是好士兵、好公民、好臣民。</strong> 瑞士人不是。西班牙人不是。意大利人也不是。好的制度造就好的材料，好的材料造就好的军队，好的军队造就好的国家。这条责任链的起点在君主——不是因为君主多么伟大，而是因为只有君主拥有改变制度的权力。如果你有权力但没有行动，那么所有下游的失败都归因于你。</p><h2 id="为什么这句话令人不舒服" tabindex="-1">为什么这句话令人不舒服 <a class="header-anchor" href="#为什么这句话令人不舒服" aria-label="Permalink to &quot;为什么这句话令人不舒服&quot;">​</a></h2><p>&quot;责在君主&quot;之所以比马基雅维利其他所有信条更让人不适，是因为它关掉了所有推卸责任的出口。不能怪民众——因为他们只不过是对自己所处的制度做出了理性的反应。不能怪机运——因为你在好天气里什么都没做。不能怪时代——因为古代的优秀君主在更糟糕的时代里做成了你做不到的事。每一个方向都被封死了。唯一剩下的就是你自己。</p><p>法布里齐奥的那句&quot;他们业已为此受到惩罚&quot;——<em>e ne hanno giustamente portata la pena</em>——在意大利语中带有一种冰冷的终局感。&quot;公正的惩罚&quot;不是未来的警告，而是已经发生的事实：可耻地亡国，全无美德的范例。这个句子没有怒气，甚至没有惋惜。它是一种陈述，就像医生告诉一个不听劝告的病人&quot;你已经死了&quot;。</p><p>也许这就是为什么马基雅维利在同时代人那里得不到欢迎的真正原因。不是因为他教君主&quot;作恶&quot;——比他教得更恶的人多的是。而是因为他坚持说：<strong>如果你的国家一团糟，那不是因为人民不行。是因为你不行。</strong></p><p><em>尼科洛·马基雅维利，圣卡夏诺</em></p>',34)])])}const m=o(p,[["render",u]]);export{c as __pageData,m as default};
